// tests/accessibility/chat-component.test.tsx
import { render } from '@testing-library/react';
import { axe, toHaveNoViolations } from 'jest-axe';
import { ChatInterface } from '../components/ChatInterface';

expect.extend(toHaveNoViolations);

describe('ChatInterface accessibility', () => {
  it('passes axe accessibility audit on initial render', async () => {
    const { container } = render(<ChatInterface />);
    const results = await axe(container);
    expect(results).toHaveNoViolations();
  });

  it('announces new AI response via ARIA live region', async () => {
    const { getByRole, findByText } = render(<ChatInterface />);
    const liveRegion = getByRole('log'); // chat transcript region
    expect(liveRegion).toHaveAttribute('aria-live', 'polite');
    // Simulate a new AI message appearing
    // Assert ARIA live region updates
  });

  it('provides skip link to input field', () => {
    const { getByText } = render(<ChatInterface />);
    const skipLink = getByText('Skip to message input');
    expect(skipLink).toBeInTheDocument();
    expect(skipLink.closest('a')).toHaveAttribute('href', '#message-input');
  });

  it('includes accessible label on message input', () => {
    const { getByLabelText } = render(<ChatInterface />);
    expect(getByLabelText('Message')).toBeInTheDocument();
  });
});

// tests/accessibility/ai-content.test.ts
// Tests that AI-generated content has required accessibility markup
import { generateChatResponse } from '../lib/agent';
import { renderMarkdown } from '../lib/renderer';
import { axe } from 'jest-axe';
import { JSDOM } from 'jsdom';

describe('AI-generated content accessibility', () => {
  it('renders AI table output with proper header markup', async () => {
    const response = await generateChatResponse(
      'Show me a comparison table of three programming languages'
    );
    const html = renderMarkdown(response.text);
    const dom = new JSDOM(html);
    const table = dom.window.document.querySelector('table');
    expect(table).toBeTruthy();
    expect(table!.querySelector('thead')).toBeTruthy();
    expect(table!.querySelectorAll('th').length).toBeGreaterThan(0);
  });

  it('renders AI code block with semantic code element', async () => {
    const response = await generateChatResponse(
      'Write a Python function that adds two numbers'
    );
    const html = renderMarkdown(response.text);
    const dom = new JSDOM(html);
    expect(dom.window.document.querySelector('pre > code')).toBeTruthy();
  });
});

/* Accessible chat bubble colour system */
:root {
  --user-bubble-bg: #2563eb;       /* Blue */
  --user-bubble-text: #ffffff;     /* White — contrast ratio 5.74:1 ✓ */
  --ai-bubble-bg: #f1f5f9;         /* Slate 100 */
  --ai-bubble-text: #1e293b;       /* Slate 800 — contrast ratio 12.1:1 ✓ */
  --timestamp-text: #64748b;       /* Slate 500 on white bg — 4.6:1 ✓ */
}

/* Respect reduced motion for typing indicator */
@media (prefers-reduced-motion: reduce) {
  .typing-indicator-dot {
    animation: none;
    opacity: 1;
  }
}

/* Dark mode — verify contrast ratios independently */
@media (prefers-color-scheme: dark) {
  :root {
    --user-bubble-bg: #1d4ed8;     /* Blue 700 */
    --user-bubble-text: #ffffff;   /* Verify: 7.2:1 ✓ */
    --ai-bubble-bg: #1e293b;       /* Slate 800 */
    --ai-bubble-text: #f1f5f9;     /* Slate 100 — 11.8:1 ✓ */
  }
}
